"use client";

import { Category, Dish, MenuForm, } from "@/data/types/dishMenu";
import { Box, Button, Flex, TextArea, TextField } from "@radix-ui/themes";
import { useFieldArray, UseFormReturn } from "react-hook-form";
import ErrorLabel from "./label/ErrorLabel";
import { MoveUpIcon, PlusIcon, TrashIcon, UploadIcon } from "lucide-react";

type FormCategoryProps = {
    form: UseFormReturn<MenuForm, any, MenuForm>,
    index: number,
    category: Category
    onRemoveCategory: () => void
    isSaved?: (value: boolean) => void
}

const CategoryForm = ({ form, index, isSaved, category, onRemoveCategory }: FormCategoryProps) => {
    const { control, register, formState: { errors } } = form
    const {
        append,
        remove: removeDish,
        fields: dishes } = useFieldArray({
            name: `categories.${index}.dishes`,
            control
        })
    const onAddNewDish = () => {
        const newDish: Dish = {
            id: crypto.randomUUID(),
            name: "",
            price: null,
            description: ""
        }
        if (isSaved)
            isSaved(false);
        append(newDish)
    }

    return <div className="border rounded-md pt-5">
        <Flex
            key={category.id}
            direction="column"
            gap="2"
            className="p-2 mt-4 border rounded-md bg-gray-50" >
            <Flex className="flex items-center gap-2" height="100px" >
                <Button
                    type="button"
                    variant="ghost"
                    size="2"
                    radius="medium"
                    color="gray"
                ><MoveUpIcon />
                </Button>
                <Box width="80vw" >
                    <TextField.Root
                        key={category.id}
                        {...register(`categories.${index}.name`)}
                        size="3"
                        placeholder="Nazwa kategori..."
                        variant="soft"
                        className="shadow-[var(--shadow-3)]"
                        color="gray"
                    />
                </Box>
                <div className=" 
                flex
                items-center
                justify-center
                w-8
                h-8
                rounded-full
                border
                border-gray-300
                text-sm
                font-medium
                self-center
                shrink-0">
                    {dishes.length}
                </div>
                <Button
                    type="button"
                    color="gray"
                    onClick={onRemoveCategory}
                    size="2"
                    radius="medium">
                    <TrashIcon></TrashIcon>
                </Button>
            </Flex>



        </Flex >
        <div className="flex justify-center  m-0 border p-10 border-solid rounded-md">

        </div>
        <div className="flex justify-center  m-0 border p-10 border-solid rounded-md">
            <Button
                onClick={onAddNewDish}
                type="button"
                color="gray"
                variant="ghost"
                size="3"
                className="
                    -full
                    py-6
                    bg-transparent
                    hover:bg-transparent
                    focus:bg-transparent
                    active:bg-transparent
                    focus:outline-none
                    focus:ring-0
                    shadow-none
                    "
            ><PlusIcon />
                Add first dish
            </Button>
        </div>
    </div>
}

export default CategoryForm